class TestZeroSampleExtended(unittest.TestCase):
    def _d(self, offset):
        import datetime
        from learning_loop.adapter import SYSTEM_START_DATE
        return SYSTEM_START_DATE + datetime.timedelta(days=offset)
    def test_triggers_at_10_days_zero_trades(self):
        from learning_loop.adapter import heuristic_zero_sample_extended
        fired, msg = heuristic_zero_sample_extended("momentum-long", {"enabled": True, "trades_lifetime": 0}, today=self._d(10))
        self.assertTrue(fired)
        self.assertIn("momentum-long", msg)
    def test_no_trigger_at_9_days(self):
        from learning_loop.adapter import heuristic_zero_sample_extended
        fired, _ = heuristic_zero_sample_extended("momentum-long", {"enabled": True, "trades_lifetime": 0}, today=self._d(9))
        self.assertFalse(fired)
    def test_no_trigger_at_zero_days(self):
        from learning_loop.adapter import SYSTEM_START_DATE, heuristic_zero_sample_extended
        fired, _ = heuristic_zero_sample_extended("momentum-long", {"enabled": True, "trades_lifetime": 0}, today=SYSTEM_START_DATE)
        self.assertFalse(fired)
    def test_no_trigger_when_disabled(self):
        from learning_loop.adapter import heuristic_zero_sample_extended
        fired, _ = heuristic_zero_sample_extended("momentum-long", {"enabled": False, "trades_lifetime": 0}, today=self._d(15))
        self.assertFalse(fired)
    def test_no_trigger_when_trades_exist(self):
        from learning_loop.adapter import heuristic_zero_sample_extended
        fired, _ = heuristic_zero_sample_extended("momentum-long", {"enabled": True, "trades_lifetime": 1}, today=self._d(15))
        self.assertFalse(fired)
